function serve(hit,req){return fetch(hit[0]).then(function(r){return r.arrayBuffer();}).then(function(buf){return resp(buf,req,hit[1]);}).catch(function(){return new Response("",{status:404});});}
var SBUF=null;
function silentBuf(){if(SBUF)return SBUF;var bin=atob(SILENT);var u8=new Uint8Array(bin.length);for(var i=0;i<bin.length;i++)u8[i]=bin.charCodeAt(i);SBUF=u8.buffer;return SBUF;}
self.addEventListener("fetch",function(ev){
  var u;try{u=new URL(ev.request.url);}catch(e){return;}
  if(u.protocol.indexOf("http")!==0)return;
  var same=u.origin===self.location.origin;
  if(same&&(u.pathname=="/sw.js"||u.pathname=="/live.html"||u.pathname.indexOf("/live-assets/")==0))return;
  if(TRACK.test(u.href)){ev.respondWith(new Response(null,{status:204}));return;}
  var key=same?(u.pathname+u.search):u.href;
  var alt=same?u.pathname:(u.origin+u.pathname);
  var hit=M[key]||M[alt]||FUZZ[u.pathname]||BASE[u.pathname.split("/").pop()]||NORM[norm(key)]||NORM[norm(alt)];
  if(hit){ev.respondWith(serve(hit,ev.request));return;}
  if(AUDIO.test(u.pathname)||u.pathname.indexOf("/music/")>=0){ev.respondWith(resp(silentBuf(),ev.request,"audio/mpeg"));return;}
  if(!same)ev.respondWith(new Response("",{status:404}));
});
